        console.log(`Received: ${message}`);
    });
    socket.send('Hello! Message from server.');
});
```

Graph data structure ek collection hota hai nodes (vertices) aur edges ka. Ye relationship ko represent karne ke liye use hota hai, jese social networks, maps, aur websites ke links. Graph ko represent karne ke do tareeqe hain: adjacency list aur adjacency matrix. Yeh raha ek adjacency list ka example:

```python
class Graph:
    def __init__(self):
        self.graph = {}

    def add_edge(self, u, v):
        if u in self.graph:
            self.graph[u].append(v)
        else:
            self.graph[u] = [v]

    def print_graph(self):
        for node in self.graph:
            print(node, "->", " -> ".join(map(str, self.graph[node])))

# Graph ka istemal
g = Graph()
g.add_edge(0, 1)
g.add_edge(0, 2)
g.add_edge(1, 2)
g.print_graph()
```

