     method: 'PUT',
     headers: {
       'Content-Type': 'application/json',
     },
     body: JSON.stringify({ age: 31 }),
   })
   .then(response => response.json())
   .then(data => console.log(data));
   ```

4. **DELETE**: Data ko delete karne ke liye istemal hota hai. Jaise, kisi user ko delete karna: 
   ```javascript
   fetch('https://api.example.com/users/1', {
     method: 'DELETE',
   })
   .then(response => response.json())
   .then(data => console.log(data));
   ```

React mein Todo app banane ke liye aapko state management ka use karna hoga. Hum useState hook ka istemal karenge. Aayiye ek simple example dekhte hain:

```javascript
import React, { useState } from 'react';

function TodoApp() {
  const [todos, setTodos] = useState([]);
  const [inputValue, setInputValue] = useState('');

  const addTodo = () => {
    setTodos([...todos, inputValue]);
    setInputValue('');
  };

  return (
    <div>
      <input
        type="text"
        value={inputValue}
        onChange={(e) => setInputValue(e.target.value)}
      />
      <button onClick={addTodo}>Add Todo</button>
      <ul>
        {todos.map((todo, index) => (
          <li key={index}>{todo}</li>
        ))}
      </ul>
    </div>
  );
}

export default TodoApp;
```
Is example mein, humne ek input field aur button banaya hai jisse users naya todo item add kar sakte hain aur wo list mein display hoga.

CSS Grid layout ek powerful tool hai jo aapko complex layouts banane mein madad karta hai. Yeh aapko rows aur columns mein elements ko organize karne ki flexibility deta hai. Chaliye dekhte hain kaise use karte hain:

1. Pehle aapko apne container ko grid banane ki zaroorat hai:
   ```css
   .grid-container {
       display: grid;
       grid-template-columns: repeat(3, 1fr);
       grid-gap: 10px;
   }
   ```
   Ismein `grid-template-columns` ka istemal karke humne teen columns banaye hain.

2. Ab aap apne grid items ko is tarah set kar sakte hain:
   ```css
   .grid-item {
       background-color: lightblue;
       padding: 20px;
       text-align: center;
   }
   ```

3. HTML mein aapka structure kuch is tarah hoga:
   ```html
   <div class="grid-container">
       <div class="grid-item">1</div>
       <div class="grid-item">2</div>
       <div class="grid-item">3</div>
       <div class="grid-item">4</div>
       <div class="grid-item">5</div>
       <div class="grid-item">6</div>
   </div>
   ```

Iss tarah aap CSS Grid ka istemal karke asani se layouts design kar sakte hain jo responsive aur flexible hote hain.

Cloudflare Workers ek serverless platform hai jo developers ko apni applications ko easily deploy karne ki sahulat deti hai. Ye JavaScript ya WebAssembly mein likhi gayi scripts ko run karte hain jo Cloudflare ki global network par host hoti hain. Inka use speed, performance, aur security ke liye hota hai.

Jaise agar aapko ek API create karni hai jo kisi bhi request ko process kare, to aap Cloudflare Workers ka istemal kar sakte hain. Iska basic example:

```javascript
addEventListener('fetch', event => {
    event.respondWith(handleRequest(event.request))
})

async function handleRequest(request) {
    return new Response('Hello, World!', { status: 200 })
}
```

Is example mein `fetch` event ko listen kiya gaya hai aur jab bhi koi request aaye, `handleRequest` function ko call kiya jaata hai jo ek simple response de raha hai. Ye sab kuch bina kisi server ke hota hai!

HTTP methods ka farq samajhne ke liye, chalo in chaaron methods ko dekhtay hain:

1. **GET**: Yeh method server se data lene ke liye hota hai. Jaise agar aapko kisi website ka content dekhna hai, to aap GET request bhejte hain.

   Example:
   ```javascript
